import randomfrom threeML.io.logging import setup_loggerlog = setup_logger(__name__)from KRAFit.BestFits.JointLikelihood import JLfrom KRAFit.BestFits.RealData import RealDataclass RealJL(RealData, JL):        def __init__(self, model, num_starts = 1, stat_types = ['Fit'], start_values = {}, **kwargs):                super().jl_info(start_values)                super().__init__(model, num_starts, stat_types, **kwargs)                return            def setup_method_info(self):        return            def _best_fits_path(self, key, source_start, source_stop, flags) -> str:        return '{results_path}/best_fit_params/{0}/GRB{number}_{method_model}_params_{num_params}_best_fit_params_{1}_{bin_method}_{bin_var}_time_{2}-{3}{4}.csv'.format(self.method, key, source_start, source_stop, self.save_extension_setter(flags['save_extension']), **self._save_vars)                def save_vars_extend(self, index, **kwargs):                i, j = index[0], index[1]                bsn_kra = kwargs.get('bsn_kra', None)                if j == self.num_starts - 1:            for param in self.start_values:                self.start_values[param][-1] = bsn_kra._results['value'].loc[(i, 0, 'Fit'), param]                log.info('Set start values to bsn kra ultra/emcee')                start_info = 'init_params_' + '_'.join(['{0}_{1}'.format(param, round(self.start_values[param][j], 3)) for param in self.start_values])        save_vars_extended = super().save_vars_extend(index, start_info)                save_vars_extended['start_values'] = start_info        # save_vars_extended['sampler_params'] = ''                    return save_vars_extended            def _fit_setup(self, index, save_vars_extended, **kwargs):                i, j = index[0], index[1]                bsn_kra = kwargs.get('bsn_kra')        if self.start_values != {}:            for param in self.parameters:                if param in self.free_parameters:                    # Used to start fit at the best bayesian result                    if j == self.num_starts - 1:                        self.start_values[param][j] = bsn_kra._results['value'].loc[(i, 0, 'Fit'), param]                        a = random.uniform(0.9, 1.1)                        print(a)                        try:                            self.model.spectra[param].value = self.start_values[param][j] * a                        except:                            self.model.spectra[param].value = self.start_values[param][j]                        log.info('Start value: {0} = {1}'.format(param, self.model.spectra[param].value))                    else:                        self.model.spectra[param].value = self.start_values[param][j]                        log.info('Start value: {0} = {1}'.format(param, self.model.spectra[param].value))                else:                    self.model.spectra[param].value = self._results['value'].loc[(i, j, 'Fit'), param]                    log.info('Fixed value: {0} = {1}'.format(param, self.model.spectra[param].value))                            else:            pass                        file_exists, path_fit_file = super()._fit_setup(index, save_vars_extended, **kwargs)                return file_exists, path_fit_file            def _perform_fit(self, index):        return self.perform_fit(index[0])            def _fit_plots(self, index, samples, flags, **kwargs):        return super()._fit_plots(index, flags, **kwargs)            